mapper.select:
SELECT wq.*, q.title AS question_title, q.content AS question_content, qt.name AS question_type, q.difficulty AS question_difficulty, q.options AS question_options, q.correct_answers, q.correct_answer, q.tags AS question_tags FROM wrong_questions wq JOIN questions q ON wq.question_id = q.id JOIN question_types qt ON q.type_id = qt.id WHERE wq.student_id = #{studentId}
AND wq.mastered = #{mastered}
ORDER BY wq.updated_time DESC

mapper.update:
UPDATE wrong_questions
exam_id = #{examId}, wrong_count = #{wrongCount}, mastered = #{mastered}, last_wrong_answer = #{lastWrongAnswer}, updated_time = NOW()
WHERE id = #{id}

UPDATE wrong_questions
SET mastered = #{mastered}, updated_time = NOW()
WHERE student_id = #{studentId} AND question_id = #{questionId}
